Get-ChildItem -Recurse -Include *.py, *.js, *.jsx, *.ts, *.tsx, *.json, *.md, *.txt, *.yaml, *.yml, *.css, *.html, *.npz, *.jsonl | Where-Object { $_.FullName -notmatch "\\venv\\|\\__pycache__\\|\\\.git\\|\\\.pytest_cache\\|\\artifacts\\|\\node_modules\\|\\dist\\|\\build\\|\\\.next\\|\\jepa_weights\.npz|\\\.vs\\" } | ForEach-Object { "===== $($_.FullName) ====="; Get-Content $_.FullName -ErrorAction SilentlyContinue; "" } | Out-File -FilePath "$env:USERPROFILE\Desktop\semantic_ai_final_export.txt" -Encoding utf8